patch:
--- a/mux_selector.v
+++ b/mux_selector.v
@@ -1,12 +1,12 @@
 module mux_selector(
     input [31:0] data_in_0,
     input [31:0] data_in_1,
     input [31:0] data_in_2,
     input [31:0] data_in_3,
     input [1:0] select,
     output reg [31:0] mux_out
 );
-    always @(data_in_0 or data_in_1) begin
+    always @(data_in_0 or data_in_1 or data_in_2 or data_in_3 or select) begin
         case(select)
             2'b00: mux_out = data_in_0;
             2'b01: mux_out = data_in_1;
             2'b10: mux_out = data_in_2;
             2'b11: mux_out = data_in_3;
             default: mux_out = 32'b0;
         endcase
     end
 endmodule

before_code:
module mux_selector(
    input [31:0] data_in_0,
    input [31:0] data_in_1,
    input [31:0] data_in_2,
    input [31:0] data_in_3,
    input [1:0] select,
    output reg [31:0] mux_out
);
    always @(data_in_0 or data_in_1) begin
        case(select)
            2'b00: mux_out = data_in_0;
            2'b01: mux_out = data_in_1;
            2'b10: mux_out = data_in_2;
            2'b11: mux_out = data_in_3;
            default: mux_out = 32'b0;
        endcase
    end
endmodule

after_code:
